// App.js
// Componente raiz da aplicação.
// Controla qual tela está ativa (shows ou fechamento).

import { useState, useEffect, useCallback } from 'react';
import ShowForm from './components/ShowForm';
import ShowList from './components/ShowList';
import FechamentoMensal from './components/FechamentoMensal';
import { getShows } from './services/api';
import './App.css';

export default function App() {
  const [pagina, setPagina] = useState('shows');
  const [shows, setShows] = useState([]);
  const [loadingShows, setLoadingShows] = useState(false);

  // Busca os shows do backend
  const carregarShows = useCallback(async () => {
    setLoadingShows(true);
    try {
      const data = await getShows();
      setShows(data);
    } catch (err) {
      console.error('Erro ao carregar shows:', err);
    } finally {
      setLoadingShows(false);
    }
  }, []);

  // Carrega os shows assim que a página de shows é acessada
  useEffect(() => {
    if (pagina === 'shows') {
      carregarShows();
    }
  }, [pagina, carregarShows]);

  return (
    <div className="app">
      <header className="header">
        <div className="header-inner">
          <div className="logo">
            <span className="logo-icon">🎧</span>
            <span className="logo-text">DRUDS</span>
            <span className="logo-sub">Financeiro</span>
          </div>

          <nav className="nav">
            <button
              className={`nav-btn ${pagina === 'shows' ? 'active' : ''}`}
              onClick={() => setPagina('shows')}
            >
              Shows
            </button>
            <button
              className={`nav-btn ${pagina === 'fechamento' ? 'active' : ''}`}
              onClick={() => setPagina('fechamento')}
            >
              Fechamento
            </button>
          </nav>
        </div>
      </header>

      <main className="main">
        {pagina === 'shows' && (
          <div className="page">
            <ShowForm onShowCriado={carregarShows} />
            <ShowList
              shows={shows}
              loading={loadingShows}
              onShowDeletado={carregarShows}
            />
          </div>
        )}

        {pagina === 'fechamento' && (
          <div className="page">
            <FechamentoMensal />
          </div>
        )}
      </main>
    </div>
  );
}
